mapper.delete:
delete from activity_plan
where id in

    #{id}

mapper.select:
select id, plan_name, min_age, max_age,
       activity_category, season, duration,
       scene, status,
       create_time, update_time, create_user, update_user
from activity_plan


        and plan_name like concat('%',#{planName},'%')


        and activity_category = #{activityCategory}


        and status=#{status}


        and (season & #{season})!=0


        and scene=#{scene}


        and min_age >= #{minAge}


        and max_age <= #{maxAge}


        and duration >= #{minDuration}


        and duration <= #{maxDuration}


order by create_time asc

select count(*)
from activity_plan
where create_time >= #{startTime}
  and create_time < #{endTime}
